import type { Metadata } from "next"
import { BookingManageApp } from "./BookingManageApp"

export const metadata: Metadata = {
  title: "予約・マイレージ | 群青エア マイレージクラブ",
  description:
    "ご予約の確認・変更・取消、座席変更、マイル残高と獲得・利用履歴の確認、特典航空券への交換ができる会員向け画面。",
}

// Server Component shell. すべての対話ロジックと関数 prop（onValueChange /
// onSelect / onOpenChange など）は "use client" 境界の BookingManageApp 内に閉じ、
// next build が関数のシリアライズで失敗しないようにしている。
export default function BookingManagePage() {
  return (
    <main className="min-h-screen bg-muted/30">
      <BookingManageApp />
    </main>
  )
}

"use client"

import * as React from "react"
import {
  IconPlaneDeparture,
  IconArrowRight,
  IconChevronRight,
  IconGift,
  IconCrown,
  IconAlertTriangle,
  IconArmchair2,
  IconUser,
  IconCalendarEvent,
  IconExchange,
} from "@tabler/icons-react"

import {
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  ListCard,
  Badge,
  Button,
  Card,
  CardContent,
  Meter,
  Statistic,
  MetadataList,
  AmountBreakdown,
  Separator,
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
  DrawerDescription,
  DrawerFooter,
  DrawerClose,
  formatNumber,
} from "@gunjo/ui"

import {
  member,
  bookings,
  mileageTxns,
  rewards,
  type Booking,
  type BookingStatus,
} from "./data"

/* ---------------------------------------------------------------- helpers */

const STATUS_META: Record<
  BookingStatus,
  { label: string; variant: "info" | "success" | "destructive" | "warning"; severity?: "info" | "success" | "warning" | "critical" }
> = {
  upcoming: { label: "搭乗予定", variant: "info", severity: "info" },
  flown: { label: "搭乗済", variant: "success" },
  cancelled: { label: "欠航・取消", variant: "destructive", severity: "critical" },
  changed: { label: "変更済", variant: "warning", severity: "warning" },
}

const fmtMiles = (n: number) => `${formatNumber(n)} マイル`
const fmtMilesShort = (n: number) => formatNumber(n)

/* ---------------------------------------------------------------- tier card */

function TierSummary() {
  const remaining = member.nextTierPoints - member.statusPoints
  return (
    <Card className="overflow-hidden border-warning-border">
      {/* loyalty「shine」— ゴールドらしいグラデーション帯。tokenベースの色で */}
      <div className="bg-gradient-to-br from-warning-subtle via-card to-card px-4 pt-4 pb-3">
        <div className="flex items-start justify-between gap-3">
          <div className="min-w-0">
            <p className="text-xs text-muted-foreground">群青エア マイレージクラブ</p>
            <p className="mt-0.5 truncate text-base font-semibold text-foreground">{member.name} 様</p>
            <p className="mt-0.5 text-xs tabular-nums text-muted-foreground">会員番号 {member.memberNo}</p>
          </div>
          <Badge variant="warning" icon={<IconCrown aria-hidden />} className="shrink-0 px-3 py-1 text-sm font-bold">
            {member.tier}
          </Badge>
        </div>
      </div>

      <CardContent className="space-y-4 px-4 pb-4 pt-1">
        {/* 次ステータスまで — value-vs-goal を Meter(target marker)で */}
        <div>
          <div className="mb-1 flex items-baseline justify-between gap-2">
            <span className="text-sm font-medium text-foreground">
              {member.nextTier}まで あと{" "}
              <span className="tabular-nums text-warning">{formatNumber(remaining)}</span> PP
            </span>
            <span className="text-xs tabular-nums text-muted-foreground">
              {formatNumber(member.statusPoints)} / {formatNumber(member.nextTierPoints)} PP
            </span>
          </div>
          <Meter
            value={member.statusPoints}
            max={member.nextTierPoints}
            direction="fill-is-good"
            target={member.nextTierPoints}
            label={`${member.nextTier}ステータスまでの進捗`}
            showValue={false}
            unit=" PP"
          />
          <p className="mt-1.5 text-xs text-muted-foreground">
            当年の搭乗実績{" "}
            <span className="tabular-nums text-foreground">{member.segmentsFlown}</span> 区間 ・ ステータスポイント（プレミアムポイント）
          </p>
        </div>

        <Separator />

        {/* マイル残高 + 有効期限注意 */}
        <div className="flex items-end justify-between gap-3">
          <div>
            <p className="text-xs text-muted-foreground">マイル残高</p>
            <p className="text-3xl font-bold tabular-nums tracking-tight text-foreground">
              {formatNumber(member.milesBalance)}
              <span className="ml-1 text-base font-medium text-muted-foreground">マイル</span>
            </p>
          </div>
          <Badge
            variant="warning"
            icon={<IconAlertTriangle aria-hidden />}
            className="h-auto whitespace-normal py-1 text-right leading-tight"
          >
            {formatNumber(member.expiringMiles)}マイルが
            <br />
            {member.expiringDate} 失効
          </Badge>
        </div>
      </CardContent>
    </Card>
  )
}

/* ---------------------------------------------------------------- booking row */

function carrierDot(carrier: Booking["carrier"]) {
  return (
    <span
      aria-hidden
      className={
        "flex size-9 items-center justify-center rounded-full text-[11px] font-bold " +
        (carrier === "ANA" ? "bg-info-subtle text-info-subtle-foreground" : "bg-destructive-subtle text-destructive")
      }
    >
      {carrier}
    </span>
  )
}

function BookingRow({ b, onOpen }: { b: Booking; onOpen: (b: Booking) => void }) {
  const s = STATUS_META[b.status]
  return (
    <ListCard
      leading={carrierDot(b.carrier)}
      title={
        <span className="flex items-center gap-1.5">
          <span className="font-semibold tabular-nums">{b.flightNo}</span>
          <span className="text-sm font-normal tabular-nums text-foreground">
            {b.fromCode} <IconArrowRight className="inline size-3.5 align-middle text-muted-foreground" aria-label="から" /> {b.toCode}
          </span>
        </span>
      }
      description={
        <span className="tabular-nums">
          {b.dateLabel} {b.depTime}–{b.arrTime} ・ {b.passenger}
        </span>
      }
      tags={
        <>
          <Badge variant="outline" className="font-normal">
            {b.cabin}
          </Badge>
          <span className="text-xs tabular-nums text-muted-foreground">予約番号 {b.pnr}</span>
        </>
      }
      status={
        <Badge variant={s.variant} className="whitespace-nowrap">
          {s.label}
        </Badge>
      }
      meta={b.status === "upcoming" || b.status === "flown" ? `+${formatNumber(b.earnMiles)} マイル` : undefined}
      severity={s.severity}
      onSelect={() => onOpen(b)}
    />
  )
}

/* ---------------------------------------------------------------- booking detail (drawer) */

function BookingDetail({ b }: { b: Booking }) {
  const s = STATUS_META[b.status]
  const actionable = b.status === "upcoming"
  return (
    <div className="space-y-5">
      {/* 区間ヘッダ */}
      <div className="rounded-lg border bg-muted/40 p-4">
        <div className="flex items-center justify-between">
          <div className="text-center">
            <p className="text-2xl font-bold tabular-nums">{b.fromCode}</p>
            <p className="text-xs text-muted-foreground">{b.fromName}</p>
            <p className="mt-1 text-sm font-medium tabular-nums">{b.depTime}</p>
          </div>
          <div className="flex flex-1 flex-col items-center px-2 text-muted-foreground">
            <IconPlaneDeparture className="size-5" aria-hidden />
            <span className="mt-1 text-[11px] tabular-nums">{b.flightNo}</span>
            <div className="mt-1 h-px w-full bg-border" />
          </div>
          <div className="text-center">
            <p className="text-2xl font-bold tabular-nums">{b.toCode}</p>
            <p className="text-xs text-muted-foreground">{b.toName}</p>
            <p className="mt-1 text-sm font-medium tabular-nums">{b.arrTime}</p>
          </div>
        </div>
        <div className="mt-3 flex items-center justify-center gap-2">
          <Badge variant={s.variant}>{s.label}</Badge>
          <span className="text-xs tabular-nums text-muted-foreground">{b.dateLabel}</span>
        </div>
      </div>

      {/* 予約フィールド */}
      <MetadataList
        items={[
          { label: "予約番号（確認番号）", value: <span className="tabular-nums">{b.pnr}</span>, icon: <IconCalendarEvent className="size-4" aria-hidden /> },
          { label: "搭乗者", value: b.passenger, icon: <IconUser className="size-4" aria-hidden /> },
          { label: "座席", value: b.seat, icon: <IconArmchair2 className="size-4" aria-hidden /> },
          { label: "運賃種別", value: b.fareType },
          { label: "クラス", value: b.cabin },
          {
            label: "獲得マイル",
            value:
              b.earnMiles > 0 ? (
                <span className="tabular-nums text-success">+{formatNumber(b.earnMiles)} マイル</span>
              ) : (
                <span className="text-muted-foreground">—</span>
              ),
          },
        ]}
      />

      {/* 運賃内訳 */}
      <div>
        <p className="mb-2 text-sm font-medium text-foreground">運賃明細</p>
        <AmountBreakdown
          lines={b.fare.map((f) => ({ label: f.label, amount: f.amount, kind: f.kind, note: f.note }))}
          total={{ label: "お支払金額", amount: b.fareTotal }}
        />
      </div>

      {/* アクション */}
      {actionable ? (
        <div className="grid grid-cols-2 gap-2">
          <Button variant="primary" size="lg" className="w-full">
            予約変更
          </Button>
          <Button variant="outline" size="lg" className="w-full">
            座席変更
          </Button>
          <Button variant="ghost" size="lg" className="col-span-2 w-full text-destructive hover:bg-destructive-subtle">
            予約を取消
          </Button>
        </div>
      ) : (
        <p className="rounded-md bg-muted/50 p-3 text-center text-sm text-muted-foreground">
          {b.status === "flown" ? "搭乗済みの予約です。搭乗実績はマイレージに反映済みです。" : "この予約は変更できません。"}
        </p>
      )}
    </div>
  )
}

/* ---------------------------------------------------------------- mileage tab */

function MileagePanel() {
  const earned = mileageTxns.filter((t) => t.kind === "earn").reduce((a, t) => a + t.miles, 0)
  const used = mileageTxns.filter((t) => t.kind === "redeem").reduce((a, t) => a + t.miles, 0)

  return (
    <div className="space-y-6">
      {/* マイル サマリー KPI */}
      <div className="grid grid-cols-3 gap-2">
        <Card className="p-3">
          <Statistic label="残高" value={<span className="text-xl">{fmtMilesShort(member.milesBalance)}</span>} hint="マイル" />
        </Card>
        <Card className="p-3">
          <Statistic label="直近の獲得" value={<span className="text-xl">{fmtMilesShort(earned)}</span>} change={`+${formatNumber(earned)}`} trend="up" hint="マイル" />
        </Card>
        <Card className="p-3">
          <Statistic label="直近の利用" value={<span className="text-xl">{fmtMilesShort(used)}</span>} change={`−${formatNumber(used)}`} trend="down" hint="マイル" />
        </Card>
      </div>

      {/* 特典交換 entry */}
      <section aria-labelledby="rewards-h">
        <div className="mb-2 flex items-center justify-between">
          <h2 id="rewards-h" className="text-sm font-semibold text-foreground">
            マイルで交換
          </h2>
          <Button variant="link" size="sm" className="h-auto p-0">
            すべて見る
          </Button>
        </div>
        <div className="space-y-2">
          {rewards.map((r) => (
            <ListCard
              key={r.id}
              leading={
                <span className="flex size-9 items-center justify-center rounded-full bg-warning-subtle text-warning" aria-hidden>
                  <IconGift className="size-5" />
                </span>
              }
              title={r.title}
              description={r.detail}
              tags={r.tag ? <Badge variant="success">{r.tag}</Badge> : undefined}
              meta={fmtMiles(r.miles)}
              status={
                <Button variant="outline" size="sm" disabled={member.milesBalance < r.miles}>
                  交換
                </Button>
              }
              trailing={null}
            />
          ))}
        </div>
      </section>

      {/* 獲得 / 利用 履歴 */}
      <section aria-labelledby="history-h">
        <h2 id="history-h" className="mb-2 text-sm font-semibold text-foreground">
          獲得・利用の履歴
        </h2>
        <div className="space-y-2">
          {mileageTxns.map((t) => {
            const isEarn = t.kind === "earn"
            return (
              <ListCard
                key={t.id}
                leading={
                  <span
                    aria-hidden
                    className={
                      "flex size-9 items-center justify-center rounded-full " +
                      (isEarn ? "bg-success-subtle text-success" : "bg-muted text-muted-foreground")
                    }
                  >
                    {isEarn ? <IconPlaneDeparture className="size-5" /> : <IconExchange className="size-5" />}
                  </span>
                }
                title={t.label}
                description={<span className="tabular-nums">{t.date}{t.detail ? ` ・ ${t.detail}` : ""}</span>}
                meta={
                  <span className={"text-sm font-semibold tabular-nums " + (isEarn ? "text-success" : "text-foreground")}>
                    {isEarn ? "+" : "−"}
                    {formatNumber(t.miles)}
                  </span>
                }
                trailing={null}
              />
            )
          })}
        </div>
      </section>
    </div>
  )
}

/* ---------------------------------------------------------------- bookings tab */

function BookingsPanel({ onOpen }: { onOpen: (b: Booking) => void }) {
  const upcoming = bookings.filter((b) => b.status === "upcoming")
  const past = bookings.filter((b) => b.status !== "upcoming")

  return (
    <div className="space-y-6">
      <section aria-labelledby="upcoming-h">
        <div className="mb-2 flex items-center justify-between">
          <h2 id="upcoming-h" className="text-sm font-semibold text-foreground">
            搭乗予定 <span className="tabular-nums text-muted-foreground">({upcoming.length})</span>
          </h2>
          <Button variant="link" size="sm" className="h-auto p-0">
            新規予約
          </Button>
        </div>
        <div className="space-y-2">
          {upcoming.map((b) => (
            <BookingRow key={b.pnr} b={b} onOpen={onOpen} />
          ))}
        </div>
      </section>

      <section aria-labelledby="past-h">
        <h2 id="past-h" className="mb-2 text-sm font-semibold text-foreground">
          搭乗済・取消 <span className="tabular-nums text-muted-foreground">({past.length})</span>
        </h2>
        <div className="space-y-2">
          {past.map((b) => (
            <BookingRow key={b.pnr} b={b} onOpen={onOpen} />
          ))}
        </div>
      </section>
    </div>
  )
}

/* ---------------------------------------------------------------- root */

export function BookingManageApp() {
  const [tab, setTab] = React.useState("bookings")
  const [selected, setSelected] = React.useState<Booking | null>(null)
  const open = selected !== null

  const handleOpen = React.useCallback((b: Booking) => setSelected(b), [])
  const handleOpenChange = React.useCallback((next: boolean) => {
    if (!next) setSelected(null)
  }, [])

  return (
    <div className="mx-auto w-full max-w-md px-4 pb-16 pt-4">
      <header className="mb-4">
        <h1 className="text-lg font-bold text-foreground">予約・マイレージ</h1>
        <p className="text-xs text-muted-foreground">ご予約の確認・変更とマイルの管理</p>
      </header>

      <TierSummary />

      <Tabs value={tab} onValueChange={setTab} className="mt-5 border-0">
        <TabsList className="sticky top-0 z-10 grid w-full grid-cols-2 bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/80">
          <TabsTrigger value="bookings" className="min-h-11">
            予約一覧
          </TabsTrigger>
          <TabsTrigger value="mileage" className="min-h-11">
            マイレージ
          </TabsTrigger>
        </TabsList>

        <TabsContent value="bookings" className="mt-4 focus-visible:outline-none">
          <BookingsPanel onOpen={handleOpen} />
        </TabsContent>
        <TabsContent value="mileage" className="mt-4 focus-visible:outline-none">
          <MileagePanel />
        </TabsContent>
      </Tabs>

      {/* 予約詳細 — モバイルはボトムシート */}
      <Drawer open={open} onOpenChange={handleOpenChange}>
        <DrawerContent className="max-h-[92vh]">
          {selected ? (
            <>
              <DrawerHeader className="text-left">
                <DrawerTitle className="flex items-center gap-2">
                  <IconPlaneDeparture className="size-5 text-muted-foreground" aria-hidden />
                  予約詳細 <span className="tabular-nums">{selected.flightNo}</span>
                </DrawerTitle>
                <DrawerDescription className="tabular-nums">
                  予約番号 {selected.pnr} ・ {selected.fromName} → {selected.toName}
                </DrawerDescription>
              </DrawerHeader>

              <div className="overflow-y-auto px-4">
                <BookingDetail b={selected} />
              </div>

              <DrawerFooter>
                <DrawerClose asChild>
                  <Button variant="outline" size="lg" className="w-full">
                    閉じる
                  </Button>
                </DrawerClose>
              </DrawerFooter>
            </>
          ) : null}
        </DrawerContent>
      </Drawer>
    </div>
  )
}
